// Forma 1: implementar Runnable (recomendada)
public class MyTask implements Runnable {
    @Override
    public void run() {
        System.out.println("Ejecutando en: " + Thread.currentThread().getName());
    }
}
Thread t = new Thread(new MyTask());
t.start();

// Forma 2: lambda
Thread t2 = new Thread(() -> System.out.println("Lambda thread"));
t2.start();

// Crear un Daemon Thread
Thread daemonThread = new Thread(() -> {
    while (true) {
        System.out.println("Daemon running...");
        Thread.sleep(1000);
    }
});
daemonThread.setDaemon(true); // debe llamarse ANTES de start()
daemonThread.start();

// Verificar
System.out.println(daemonThread.isDaemon()); // true

public void readFile(String path) throws IOException {
    try {
        FileReader file = new FileReader(path);
        // leer archivo...
    } catch (FileNotFoundException e) {
        System.out.println("Archivo no encontrado: " + e.getMessage());
    } catch (IOException e) {
        System.out.println("Error de I/O: " + e.getMessage());
    } finally {
        System.out.println("Bloque finally siempre ejecuta");
    }
}

